    untag_resource(arn, resource_tag_keys, params::Dict{String,<:Any})

Removes tags from a Region switch resource.

# Arguments

- `arn`: The Amazon Resource Name (ARN) for a tag you remove a resource from.
- `resource_tag_keys`: Tag keys that you remove from a resource.
"""
function untag_resource end

function untag_resource(
    arn, resourceTagKeys; aws_config::AbstractAWSConfig=current_aws_config()
)
    return arc_region_switch(
        "UntagResource",
        Dict{String,Any}("arn" => arn, "resourceTagKeys" => resourceTagKeys);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function untag_resource(
    arn,
    resourceTagKeys,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return arc_region_switch(
        "UntagResource",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}("arn" => arn, "resourceTagKeys" => resourceTagKeys),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    update_plan(arn, execution_role, workflows)
    update_plan(arn, execution_role, workflows, params::Dict{String,<:Any})

Updates an existing Region switch plan. You can modify the plan's description, workflows,
execution role, recovery time objective, associated alarms, and triggers.

# Arguments

- `arn`: The Amazon Resource Name (ARN) of the plan.
- `execution_role`: The updated IAM role ARN that grants Region switch the permissions
  needed to execute the plan steps.
- `workflows`: The updated workflows for the Region switch plan.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"associatedAlarms"`: The updated CloudWatch alarms associated with the plan.
- `"description"`: The updated description for the Region switch plan.
- `"recoveryTimeObjectiveMinutes"`: The updated target recovery time objective (RTO) in
  minutes for the plan.
- `"reportConfiguration"`: The updated report configuration for the plan.
- `"triggers"`: The updated conditions that can automatically trigger the execution of the
  plan.
"""
function update_plan end

function update_plan(
    arn, executionRole, workflows; aws_config::AbstractAWSConfig=current_aws_config()
)
    return arc_region_switch(
        "UpdatePlan",
        Dict{String,Any}(
            "arn" => arn, "executionRole" => executionRole, "workflows" => workflows
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_plan(
    arn,
    executionRole,
    workflows,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return arc_region_switch(
        "UpdatePlan",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "arn" => arn, "executionRole" => executionRole, "workflows" => workflows
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    update_plan_execution(action, execution_id, plan_arn)
    update_plan_execution(action, execution_id, plan_arn, params::Dict{String,<:Any})

Updates an in-progress plan execution. This operation allows you to modify certain aspects
of the execution, such as adding a comment or changing the action.

# Arguments

- `action`: The action specified for a plan execution, for example, Switch to Graceful or
  Pause.
- `execution_id`: The execution identifier of a plan execution.
- `plan_arn`: The Amazon Resource Name (ARN) of the plan with the execution to update.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"comment"`: An optional comment about the plan execution.
"""
function update_plan_execution end

function update_plan_execution(
    action, executionId, planArn; aws_config::AbstractAWSConfig=current_aws_config()
)
    return arc_region_switch(
        "UpdatePlanExecution",
        Dict{String,Any}(
            "action" => action, "executionId" => executionId, "planArn" => planArn
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_plan_execution(
    action,
    executionId,
    planArn,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return arc_region_switch(
        "UpdatePlanExecution",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "action" => action, "executionId" => executionId, "planArn" => planArn
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    update_plan_execution_step(action_to_take, comment, execution_id, plan_arn, step_name)
    update_plan_execution_step(action_to_take, comment, execution_id, plan_arn, step_name, params::Dict{String,<:Any})

Updates a specific step in an in-progress plan execution. This operation allows you to
modify the step's comment or action.

# Arguments

- `action_to_take`: The updated action to take for the step. This can be used to skip or
  retry a step.
- `comment`: An optional comment about the plan execution.
- `execution_id`: The unique identifier of the plan execution containing the step to update.
- `plan_arn`: The Amazon Resource Name (ARN) of the plan containing the execution step to
  update.
- `step_name`: The name of the execution step to update.
"""
function update_plan_execution_step end

function update_plan_execution_step(
    actionToTake,
    comment,
    executionId,
    planArn,
    stepName;
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return arc_region_switch(
        "UpdatePlanExecutionStep",
        Dict{String,Any}(
            "actionToTake" => actionToTake,
            "comment" => comment,
            "executionId" => executionId,
            "planArn" => planArn,
            "stepName" => stepName,
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_plan_execution_step(
    actionToTake,
    comment,
    executionId,
    planArn,
    stepName,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
